proof_block:
// The synthetic ensures is
//     A ==> det_endpoint_pop_head_equal(r1, r2, post1_endpoint_perm, post2_endpoint_perm)
// where A is the conjunction of the two runs' ensures clauses.  Inside
// the body of det_endpoint_pop_head those conjuncts are *not* hypotheses
// — they are the antecedent of the synthetic implication we have to
// discharge.  Case-split on A: in the `if A { ... }` branch every
// conjunct is a real hypothesis, so we can call the module-scope
// functional-uniqueness lemma, which lines up every field referenced by
// `det_endpoint_pop_head_equal` across the two runs.  The implicit else
// branch makes the implication vacuously true.

if post1_endpoint_perm@.is_init()
    && post1_endpoint_perm@.addr() == endpoint_ptr
    && post1_endpoint_perm@.value().queue_state == pre_endpoint_perm@.value().queue_state
    && post1_endpoint_perm@.value().rf_counter == pre_endpoint_perm@.value().rf_counter
    && post1_endpoint_perm@.value().owning_threads == pre_endpoint_perm@.value().owning_threads
    && post1_endpoint_perm@.value().owning_container == pre_endpoint_perm@.value().owning_container
    && post1_endpoint_perm@.value().queue.wf()
    && post1_endpoint_perm@.value().queue.len() == pre_endpoint_perm@.value().queue.len() - 1
    && post1_endpoint_perm@.value().queue@ == pre_endpoint_perm@.value().queue@.skip(1)
    && r1.0 == pre_endpoint_perm@.value().queue@[0]
    && post1_endpoint_perm@.value().queue.unique()
    && post1_endpoint_perm@.value().queue@.no_duplicates()
    && post2_endpoint_perm@.is_init()
    && post2_endpoint_perm@.addr() == endpoint_ptr
    && post2_endpoint_perm@.value().queue_state == pre_endpoint_perm@.value().queue_state
    && post2_endpoint_perm@.value().rf_counter == pre_endpoint_perm@.value().rf_counter
    && post2_endpoint_perm@.value().owning_threads == pre_endpoint_perm@.value().owning_threads
    && post2_endpoint_perm@.value().owning_container == pre_endpoint_perm@.value().owning_container
    && post2_endpoint_perm@.value().queue.wf()
    && post2_endpoint_perm@.value().queue.len() == pre_endpoint_perm@.value().queue.len() - 1
    && post2_endpoint_perm@.value().queue@ == pre_endpoint_perm@.value().queue@.skip(1)
    && r2.0 == pre_endpoint_perm@.value().queue@[0]
    && post2_endpoint_perm@.value().queue.unique()
    && post2_endpoint_perm@.value().queue@.no_duplicates()
{
    // All conjuncts of the antecedent are in scope as hypotheses now.
    // Hand off to the module-scope functional-uniqueness lemma which
    // pins every field referenced by det_endpoint_pop_head_equal.
    lemma_endpoint_pop_head_det_eq(
        endpoint_ptr,
        pre_endpoint_perm,
        post1_endpoint_perm,
        r1,
        post2_endpoint_perm,
        r2,
    );

    // Surface each conjunct of det_endpoint_pop_head_equal so z3 sees
    // the conclusion's structural shape directly.
    assert(r1.0 == r2.0);
    assert(post1_endpoint_perm@.is_init() == post2_endpoint_perm@.is_init());
    assert(post1_endpoint_perm@.addr() == post2_endpoint_perm@.addr());
    assert(post1_endpoint_perm@.value().queue.view()
        == post2_endpoint_perm@.value().queue.view());
    assert(post1_endpoint_perm@.value().queue_state.view()
        == post2_endpoint_perm@.value().queue_state.view());
    assert(post1_endpoint_perm@.value().rf_counter
        == post2_endpoint_perm@.value().rf_counter);
    assert(post1_endpoint_perm@.value().owning_threads@
        =~= post2_endpoint_perm@.value().owning_threads@);
    assert(post1_endpoint_perm@.value().owning_container
        == post2_endpoint_perm@.value().owning_container);
}

helper_lemmas:
// Module-scope functional-uniqueness lemma for `endpoint_pop_head`.
// Takes the full ensures of two runs as `requires` and concludes the
// per-field cross-run equalities that `det_endpoint_pop_head_equal`
// references.  Every step is asserted — no `assume` anywhere.
proof fn lemma_endpoint_pop_head_det_eq(
    endpoint_ptr: EndpointPtr,
    pre_endpoint_perm: Tracked<PointsTo<Endpoint>>,
    post1_endpoint_perm: Tracked<PointsTo<Endpoint>>,
    r1: (ThreadPtr, SLLIndex),
    post2_endpoint_perm: Tracked<PointsTo<Endpoint>>,
    r2: (ThreadPtr, SLLIndex),
)
    requires
        pre_endpoint_perm@.is_init(),
        pre_endpoint_perm@.addr() == endpoint_ptr,
        pre_endpoint_perm@.value().queue.len() > 0,
        // ----- run-1 ensures -----
        post1_endpoint_perm@.is_init(),
        post1_endpoint_perm@.addr() == endpoint_ptr,
        post1_endpoint_perm@.value().queue_state == pre_endpoint_perm@.value().queue_state,
        post1_endpoint_perm@.value().rf_counter == pre_endpoint_perm@.value().rf_counter,
        post1_endpoint_perm@.value().owning_threads == pre_endpoint_perm@.value().owning_threads,
        post1_endpoint_perm@.value().owning_container == pre_endpoint_perm@.value().owning_container,
        post1_endpoint_perm@.value().queue.wf(),
        post1_endpoint_perm@.value().queue.len() == pre_endpoint_perm@.value().queue.len() - 1,
        post1_endpoint_perm@.value().queue@ == pre_endpoint_perm@.value().queue@.skip(1),
        r1.0 == pre_endpoint_perm@.value().queue@[0],
        post1_endpoint_perm@.value().queue.unique(),
        post1_endpoint_perm@.value().queue@.no_duplicates(),
        // ----- run-2 ensures -----
        post2_endpoint_perm@.is_init(),
        post2_endpoint_perm@.addr() == endpoint_ptr,
        post2_endpoint_perm@.value().queue_state == pre_endpoint_perm@.value().queue_state,
        post2_endpoint_perm@.value().rf_counter == pre_endpoint_perm@.value().rf_counter,
        post2_endpoint_perm@.value().owning_threads == pre_endpoint_perm@.value().owning_threads,
        post2_endpoint_perm@.value().owning_container == pre_endpoint_perm@.value().owning_container,
        post2_endpoint_perm@.value().queue.wf(),
        post2_endpoint_perm@.value().queue.len() == pre_endpoint_perm@.value().queue.len() - 1,
        post2_endpoint_perm@.value().queue@ == pre_endpoint_perm@.value().queue@.skip(1),
        r2.0 == pre_endpoint_perm@.value().queue@[0],
        post2_endpoint_perm@.value().queue.unique(),
        post2_endpoint_perm@.value().queue@.no_duplicates(),
    ensures
        post1_endpoint_perm@.is_init() == post2_endpoint_perm@.is_init(),
        post1_endpoint_perm@.addr() == post2_endpoint_perm@.addr(),
        post1_endpoint_perm@.value().queue.view()
            == post2_endpoint_perm@.value().queue.view(),
        post1_endpoint_perm@.value().queue_state.view()
            == post2_endpoint_perm@.value().queue_state.view(),
        post1_endpoint_perm@.value().rf_counter
            == post2_endpoint_perm@.value().rf_counter,
        post1_endpoint_perm@.value().owning_threads@
            =~= post2_endpoint_perm@.value().owning_threads@,
        post1_endpoint_perm@.value().owning_container
            == post2_endpoint_perm@.value().owning_container,
        r1.0 == r2.0,
{
    // queue.view() == self.spec_seq@ == queue@
    // Both run-queues have the same `.skip(1)` view, so their underlying
    // Seq is extensionally equal.
    assert(post1_endpoint_perm@.value().queue@
        =~= pre_endpoint_perm@.value().queue@.skip(1));
    assert(post2_endpoint_perm@.value().queue@
        =~= pre_endpoint_perm@.value().queue@.skip(1));
    assert(post1_endpoint_perm@.value().queue@
        =~= post2_endpoint_perm@.value().queue@);
    assert(post1_endpoint_perm@.value().queue.view()
        == post1_endpoint_perm@.value().queue@);
    assert(post2_endpoint_perm@.value().queue.view()
        == post2_endpoint_perm@.value().queue@);
    assert(post1_endpoint_perm@.value().queue.view()
        == post2_endpoint_perm@.value().queue.view());

    // queue_state, rf_counter, owning_threads, owning_container collapse
    // through pre.
    assert(post1_endpoint_perm@.value().queue_state
        == post2_endpoint_perm@.value().queue_state);
    assert(post1_endpoint_perm@.value().queue_state.view()
        == post1_endpoint_perm@.value().queue_state);
    assert(post2_endpoint_perm@.value().queue_state.view()
        == post2_endpoint_perm@.value().queue_state);
    assert(post1_endpoint_perm@.value().queue_state.view()
        == post2_endpoint_perm@.value().queue_state.view());
    assert(post1_endpoint_perm@.value().rf_counter
        == post2_endpoint_perm@.value().rf_counter);
    assert(post1_endpoint_perm@.value().owning_threads
        == post2_endpoint_perm@.value().owning_threads);
    assert(post1_endpoint_perm@.value().owning_threads@
        =~= post2_endpoint_perm@.value().owning_threads@);
    assert(post1_endpoint_perm@.value().owning_container
        == post2_endpoint_perm@.value().owning_container);
    assert(post1_endpoint_perm@.is_init() == post2_endpoint_perm@.is_init());
    assert(post1_endpoint_perm@.addr() == post2_endpoint_perm@.addr());

    // r1.0 == r2.0 — both equal pre.queue@[0].
    assert(r1.0 == pre_endpoint_perm@.value().queue@[0]);
    assert(r2.0 == pre_endpoint_perm@.value().queue@[0]);
    assert(r1.0 == r2.0);
}
